SELECT DISTINCT ?ally ?allyLabel WHERE { 
  wd:Q130969 wdt:P5832|wdt:P945 ?ally.
  ?ally wdt:P31/wdt:P279* wd:Q3624078.
  ?ally rdfs:label ?allyLabel.
  FILTER (LANG(?allyLabel) = "en")
}

SELECT DISTINCT ?kingdom ?kingdomLabel WHERE {
  wd:Q130969 wdt:P26 ?spouse.
  ?spouse wdt:P27 ?kingdom.
  ?kingdom wdt:P31/wdt:P279* wd:Q3624078.
  ?kingdom rdfs:label ?kingdomLabel.
  FILTER(LANG(?kingdomLabel) = "en")
  FILTER NOT EXISTS { ?kingdom wdt:P576 ?dissolved }
}

